import{w as t}from"./chunks/theme.BtQINx4n.js";import{u as n}from"./chunks/links.DUxbOuLN.js";import{a3 as i,o as r,c as a,ah as s}from"./chunks/framework.CxuAKOjO.js";const u=JSON.parse('{"title":"Obsidian WebDAV Sync","description":"WebDAV Sync is a plugin for Obsidian that syncs your vault with a WebDAV server. It excels existing solutions at more robust file handling and better performance without vendor lock-in.","frontmatter":{"layout":"project","title":"Obsidian WebDAV Sync","description":"WebDAV Sync is a plugin for Obsidian that syncs your vault with a WebDAV server. It excels existing solutions at more robust file handling and better performance without vendor lock-in.","logo":"https://github.com/hesprs/obsidian-webdav-sync/raw/main/assets/logo.svg","head":[["meta",{"name":"keywords","content":"Obsidian, Obsidian plugin, Obsidian WebDAV Sync, Obsidian WebDAV, WebDAV synchronization, cross-device sync"}]]},"headers":[],"relativePath":"projects/obsidian-webdav-sync.md","filePath":"en/projects/obsidian-webdav-sync.md","lastUpdated":1775407704000}'),l={name:"projects/obsidian-webdav-sync.md"},p=i({...l,setup(o){return n([{name:"GitHub Repository",url:"https://github.com/hesprs/obsidian-webdav-sync",icon:t,color:"#010409"}]),(d,e)=>(r(),a("div",null,[...e[0]||(e[0]=[s('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><p>Obsidian WebDAV Sync is a general-purpose &amp; bidirectional WebDAV syncing plugin for Obsidian. It is created due to the current landscape that no single plugin can reliably and conveniently sync your vault with a WebDAV server. It has following features:</p><ul><li>🔄 Bidirectional syncing between local vault and remote WebDAV</li><li>⚡ Fast syncing mode with cached acceleration for realtime syncing</li><li>📁 WebDAV explorer for exploring remote directories</li><li>🔀 Conflict handling: <ul><li>Smart merge</li><li>Latest survive</li><li>Use remote</li><li>Use local</li><li>Skip</li></ul></li><li>🚀 Strict / loose sync modes for different vault sizes</li><li>📦 Large file skipping via configurable size threshold</li><li>🔁 Reliable file handling that doesn&#39;t mess up your notes</li><li>📜 Lightweight local database empowers scalability and ensures performance</li></ul><h2 id="another-syncing-plugin" tabindex="-1">Another Syncing Plugin? <a class="header-anchor" href="#another-syncing-plugin" aria-label="Permalink to “Another Syncing Plugin?”">​</a></h2><p>As an Obsidian user working across multiple devices, I&#39;ve personally encountered the sync dilemma: finding a solution that&#39;s reliable, flexible, and doesn&#39;t compromise data integrity. After trying nearly every syncing plugin in the community, I found that each came with trade-offs that frustrated my daily workflow:</p><ul><li><strong>Remotely Save</strong> offers comprehensive features but suffers from maintenance issues and bugs—deleted files mysteriously reappearing (which is the <strong>very</strong> reason that drove me quit).</li><li><strong>Syncthing Integration</strong> provides excellent P2P syncing but requires all devices to be online simultaneously.</li><li><strong>Live Sync</strong> delivers robustness at the cost of complex server setup.</li><li><strong>Git-based solutions</strong> excels at version control but is not designed for seamless daily synchronization.</li></ul><p>Then I discovered <a href="https://github.com/nutstore/obsidian-nutstore-sync" target="_blank" rel="noreferrer">Nutstore Sync</a> — an excellent plugin, but designed for Nutstore only. I thought: why not make this general-purpose? So I forked it, extensively overhauled it for no vendor lock-in, better performance, and improved stability. What came out was <strong>Obsidian WebDAV Sync</strong>.</p><h2 id="technical-breakdown" tabindex="-1">Technical Breakdown <a class="header-anchor" href="#technical-breakdown" aria-label="Permalink to “Technical Breakdown”">​</a></h2><p>To sync an Obsidian vault to a WebDAV server is a typical <strong>decentralized coordination</strong> problem, where each client has their own copy and changes of the vault and there&#39;s no centralized resolver between. The goal is to synchronize the vaults between clients for maximum data integrity.</p><p>To address this, this plugin keeps a record of the last known sync state of local and remote files. During syncing evaluates <strong>four states (current local, current remote, recorded local, recorded remote)</strong> for each file path and decides the sync action accordingly:</p><blockquote><p>✅ = Exists, ❌ = Doesn&#39;t Exist, ✏️ = Changed Compared to Record</p></blockquote><table tabindex="0"><thead><tr><th>Cases</th><th style="text-align:center;">Local File</th><th style="text-align:center;">Remote File</th><th style="text-align:center;">Sync Record</th><th>Action</th></tr></thead><tbody><tr><td>1</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>⏭️ <strong>Skip</strong> (already synced)</td></tr><tr><td>2</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⚠️ <strong>Resolve Conflict</strong> (apply strategy)</td></tr><tr><td>3</td><td style="text-align:center;">✅</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⬇️ <strong>Pull</strong> (download remote)</td></tr><tr><td>4</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>⬆️ <strong>Push</strong> (upload local)</td></tr><tr><td>5</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>🗑️ <strong>Delete Local</strong> (cleanup)</td></tr><tr><td>6</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td><td>🗑️ <strong>Delete Remote</strong> (cleanup)</td></tr><tr><td>7</td><td style="text-align:center;">❌</td><td style="text-align:center;">✏️</td><td style="text-align:center;">✅</td><td>⬇️ <strong>Pull</strong> (restore from remote)</td></tr><tr><td>8</td><td style="text-align:center;">✏️</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>⬆️ <strong>Push</strong> (restore to remote)</td></tr><tr><td>9</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅ (comparing with local)</td><td style="text-align:center;">❌</td><td>📝 <strong>Record</strong> (capture unrecorded file)</td></tr><tr><td>10</td><td style="text-align:center;">✅</td><td style="text-align:center;">✏️ (compared with local)</td><td style="text-align:center;">❌</td><td>⚠️ <strong>Resolve Conflict</strong> (first sync)</td></tr><tr><td>11</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td>⬇️ <strong>Pull</strong> (new remote file)</td></tr><tr><td>12</td><td style="text-align:center;">✅</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td>⬆️ <strong>Push</strong> (new local file)</td></tr><tr><td>13</td><td style="text-align:center;">❌</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td>🧹 <strong>Clean Record</strong> (database cleanup)</td></tr></tbody></table><p>Now the syncing is reliable enough, but some new issues emerged.</p><p>For example, comparing four states before syncing means we need a <strong>whole WebDAV, local vault and record traversal at the start of each sync</strong>, which is impractical for large vaults. To address this, <strong>Fast Mode</strong> is introduced that reuses the remote state in the record as current state. This avoids traversing the whole WebDAV, but it ignores remote changes. So <strong>a normal sync before fast syncs is recommended</strong>.</p><p>Moreover, to store the records and content of all files (to compare and decide whether a file is changed) requires a huge and active amount of storage to ensure fidelity. This plugin leverages IndexedDB to store the records and query them on-demand.</p><p>Then, more issues emerged: what if the file changes between the time of traversal and execution? What if the file becomes a folder at remote? If later changes to storage are made, how to migrate users&#39; data? There&#39;s a lot more to discuss about.</p><h2 id="installation-setup" tabindex="-1">Installation &amp; Setup <a class="header-anchor" href="#installation-setup" aria-label="Permalink to “Installation &amp; Setup”">​</a></h2><p>Since the plugin is currently in beta, installation requires the <strong>BRAT</strong> (Beta Reviewer Auto-update Tool) plugin:</p><h3 id="step-1-install-brat" tabindex="-1">Step 1: Install BRAT <a class="header-anchor" href="#step-1-install-brat" aria-label="Permalink to “Step 1: Install BRAT”">​</a></h3><ol><li>Open Obsidian Settings → Community Plugins</li><li>Search for and install <strong>BRAT</strong></li><li>Enable the plugin</li></ol><h3 id="step-2-add-obsidian-webdav-sync" tabindex="-1">Step 2: Add Obsidian WebDAV Sync <a class="header-anchor" href="#step-2-add-obsidian-webdav-sync" aria-label="Permalink to “Step 2: Add Obsidian WebDAV Sync”">​</a></h3><ol><li>Open BRAT settings</li><li>Click <strong>Add beta plugin</strong></li><li>Paste repository URL: <code>https://github.com/hesprs/obsidian-webdav-sync</code></li><li>Select the latest version and click <strong>Add plugin</strong></li></ol><h3 id="step-3-configure-webdav-connection" tabindex="-1">Step 3: Configure WebDAV Connection <a class="header-anchor" href="#step-3-configure-webdav-connection" aria-label="Permalink to “Step 3: Configure WebDAV Connection”">​</a></h3><ol><li>Enter your WebDAV server URL</li><li>Provide account credentials</li><li>Click <strong>Check connection</strong> to verify</li><li>Select your remote directory</li><li>Initiate your first sync</li></ol><blockquote><p>Always backup important notes before your initial sync. While the plugin handles file presence resolution robustly, having a backup provides peace of mind during first-time setup.</p></blockquote><h2 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to “License”">​</a></h2><p>Obsidian WebDAV Sync is licensed under the <a href="https://www.gnu.org/licenses/agpl-3.0.en.html" target="_blank" rel="noreferrer">AGPL-3.0 License</a>.</p>',27)])]))}});export{u as __pageData,p as default};
